const htmlBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const raw = htmlBuffer.toString('utf8');

let state;
try {
  state = JSON.parse(raw);
} catch (e) {
  return [{ json: { shouldExpire: false, skipReason: 'json invalido' } }];
}

const stateFileName = $input.item.binary.data.fileName || '';
const isExpired = state.estado === 'preview' && state.expires_at && new Date(state.expires_at).getTime() < Date.now();

if (!isExpired) {
  return [{ json: { shouldExpire: false, landingId: state.landing_id, stateFileName } }];
}

state.estado = 'expirado';

function escapeHtml(unsafe) {
  if (!unsafe) return '';
  return String(unsafe).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}
const corretorNome = escapeHtml(state.cliente?.corretor?.nome || '');
const corretorWa = String(state.cliente?.corretor?.whatsapp || '').replace(/\D/g, '');
const titulo = escapeHtml(state.imovel?.titulo || 'Este imóvel');
const waLink = 'https://wa.me/' + corretorWa + '?text=' + encodeURIComponent('Olá, a pré-visualização de "' + (state.imovel?.titulo || '') + '" expirou. Gostava de a reativar.');

const expiredHtml = `<!DOCTYPE html>
<html lang="pt">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Pré-visualização expirada</title>
<meta name="robots" content="noindex">
<style>
  body{font-family:system-ui,sans-serif;background:#0f172a;color:#f8fafc;display:flex;min-height:100vh;align-items:center;justify-content:center;margin:0;padding:1.5rem;text-align:center}
  .box{max-width:32rem}
  h1{font-size:1.5rem;margin-bottom:.75rem}
  p{color:#94a3b8;margin-bottom:1.5rem;line-height:1.6}
  a{display:inline-flex;align-items:center;gap:.5rem;padding:.9rem 1.5rem;border-radius:.5rem;background:#25D366;color:#062611;font-weight:600;text-decoration:none}
</style>
</head>
<body>
  <div class="box">
    <h1>A pré-visualização de "${titulo}" expirou</h1>
    <p>Esta landing estava em modo de pré-visualização e o prazo terminou sem confirmação de publicação. Contacte ${corretorNome || 'o corretor'} para a reativar.</p>
    <a href="${waLink}">Reativar via WhatsApp</a>
  </div>
</body>
</html>`;

const htmlFileName = stateFileName.replace('.state.json', '.html');
const stateFileNameOut = stateFileName;

const outHtmlBinary = await this.helpers.prepareBinaryData(Buffer.from(expiredHtml, 'utf8'), htmlFileName.split('/').pop(), 'text/html');
const outStateBinary = await this.helpers.prepareBinaryData(Buffer.from(JSON.stringify(state, null, 2), 'utf8'), stateFileNameOut.split('/').pop(), 'application/json');

return [{
  json: { shouldExpire: true, landingId: state.landing_id, htmlPath: '/home/node/.n8n-files/builds/' + htmlFileName.split('/').pop(), statePath: '/home/node/.n8n-files/builds/' + stateFileNameOut.split('/').pop() },
  binary: { data: outHtmlBinary, state: outStateBinary }
}];
